// ═══════════════════════════════════════════════════════════════════════════
// ★ CONFIGURATION
// ═══════════════════════════════════════════════════════════════════════════

const BASE         = "images";
const PREVIEWS     = "00-previews";
const GENDER_DIR   = BASE + "/01-gender";
const SKINTONE_DIR = BASE + "/02-skintone";
const HAIR_DIR     = BASE + "/03-hair";
const GLASSES_DIR  = BASE + "/05-glasses";
const OUTFITS_DIR  = BASE + "/06-outfits";
const ACCS_DIR     = BASE + "/07-accessories";
const WATERMARK_SRC = BASE + "/Watermark.jpg";

function preview(filename) { return PREVIEWS + "/Preview-" + filename + ".png"; }

const BRAND_COLORS = [
  { hex: "#f6d1cb", label: "Blush"  },
  { hex: "#f0ce5b", label: "Yellow" },
  { hex: "#3351c6", label: "Blue"   },
  { hex: "#c2221b", label: "Red"    },
  { hex: "#1c7b1c", label: "Green"  },
  { hex: "#d77326", label: "Orange" },
  { hex: "#FFFFFF", label: "White"  },
  { hex: "#2c2420", label: "Ink"    },
];

const DEFAULT_TEXT_COLOR = "#2c2420";

const SKIN_TONES = [
  { id: "Fair",     color: "#f5d5b8" },
  { id: "Tan",      color: "#d4956a" },
  { id: "Caramel",  color: "#a0622a" },
  { id: "Chestnut", color: "#6b3a1f" },
];

const HAIR_COLORS = [
  { id: "Black",  color: "#1a1a1a" },
  { id: "Brown",  color: "#6b3a2a" },
  { id: "Auburn", color: "#9b3f1e" },
  { id: "Blonde", color: "#c9a84c" },
  { id: "Grey",   color: "#8a8a8a" },
];

const HAIRSTYLES = {
  Female: ["Bob", "Loose", "Wavy", "Elegant", "None"],
  Male:   ["Tousled", "Sleek", "Classic", "Curls", "None"],
};

const OUTFITS = ["Smart", "Shimmery", "Striped", "Blazer", "Casual"];

const ACCESSORIES = ["None", "Balloons", "Gift Box", "Champagne"];

const PRINT_W = 874;
const PRINT_H = 1240;

// ═══════════════════════════════════════════════════════════════════════════
// STATE
// ═══════════════════════════════════════════════════════════════════════════
const state = {
  gender:    "Female",
  skin:      "Fair",
  glasses:   false,
  hairColor: "Black",
  hair:      "Bob",
  outfit:    "Smart",
  accessory: "None",
  recipient: "",
  message:   "",
  textColor: DEFAULT_TEXT_COLOR,
};

// ═══════════════════════════════════════════════════════════════════════════
// ASSET PATHS — all driven by state.gender
// ═══════════════════════════════════════════════════════════════════════════
function g()             { return state.gender; }
function skinSrc()       { return SKINTONE_DIR + "/" + g() + "-Birthday-Skintone-" + state.skin + ".png"; }
function hairSrc()       { return HAIR_DIR     + "/" + g() + "-Birthday-" + state.hairColor + "-" + state.hair.replace(/ /g, "-") + ".png"; }
function glassesSrc()    { return GLASSES_DIR  + "/" + g() + "-Glasses-Birthday-Adult.png"; }
function outfitSrc()     { return OUTFITS_DIR  + "/" + g() + "-Birthday-" + state.outfit + ".png"; }
function accSrc()        { return ACCS_DIR     + "/" + g() + "-Birthday-" + state.accessory + ".png"; }

function skinPreview(s)  { return preview(g() + "-Birthday-Skintone-" + s); }
function hairPreview(c, s) { return preview(g() + "-Birthday-" + c + "-" + s.replace(/ /g, "-")); }
function outfitPreview(o){ return preview(g() + "-Birthday-" + o); }
function accPreview(a)   { return preview(g() + "-Birthday-" + a); }
function genderPreview(gen) { return GENDER_DIR + "/Birthday-" + gen + ".png"; }

// ═══════════════════════════════════════════════════════════════════════════
// DOM REFS
// ═══════════════════════════════════════════════════════════════════════════
const cardWrap       = document.getElementById("card-wrap");
const layerSkin      = document.getElementById("layer-skin");
const layerOutfit    = document.getElementById("layer-outfit");
const layerHair      = document.getElementById("layer-hair");
const layerGlasses   = document.getElementById("layer-glasses");
const layerAcc       = document.getElementById("layer-acc");
const recipientText  = document.getElementById("recipient-text");
const messageText    = document.getElementById("message-text");
const recipientInput = document.getElementById("recipient-input");
const messageInput   = document.getElementById("message-input");
const recipientCount = document.getElementById("recipient-count");
const messageCount   = document.getElementById("message-count");
const glassesToggle  = document.getElementById("glasses-toggle");
const glassesLabel   = document.getElementById("glasses-label");
const saveBtn        = document.getElementById("save-btn");
const resetBtn       = document.getElementById("reset-btn");

// ═══════════════════════════════════════════════════════════════════════════
// RENDER
// ═══════════════════════════════════════════════════════════════════════════
function render() {
  cardWrap.style.background = "#fdfaf8";
  cardWrap.style.backgroundImage = "url(" + WATERMARK_SRC + ")";
  cardWrap.style.backgroundSize = "cover";
  cardWrap.style.backgroundPosition = "center";

  setLayer(layerSkin,   skinSrc());
  setLayer(layerOutfit, outfitSrc());
  if (state.hair !== "None") {
    setLayer(layerHair, hairSrc());
  } else {
    layerHair.style.display = "none";
  }

  if (state.glasses) {
    setLayer(layerGlasses, glassesSrc());
  } else {
    layerGlasses.style.display = "none";
  }

  if (state.accessory !== "None") {
    setLayer(layerAcc, accSrc());
  } else {
    layerAcc.style.display = "none";
  }

  recipientText.setAttribute("fill", state.textColor);
  messageText.setAttribute("fill", state.textColor);
  recipientText.textContent = state.recipient ? state.recipient.toUpperCase() : "";
  messageText.textContent   = state.message || "";

  fitSvgText(recipientText, cardWrap, 0.022, 0.008);
  fitSvgText(messageText,   cardWrap, 0.09,  0.045);
}

function setLayer(el, src) {
  el.src = src;
  el.style.display = "block";
}

function fitSvgText(el, container, startRatio, minRatio) {
  setTimeout(() => {
    const w = container.offsetWidth;
    const h = container.offsetHeight;
    if (!w || !h) return;
    const maxWidth = Math.round(w * 0.82);
    let size = Math.round(h * startRatio);
    const min = Math.round(h * minRatio);
    el.setAttribute("font-size", size);
    el.removeAttribute("textLength");
    while (el.getComputedTextLength() > maxWidth && size > min) {
      size -= 1;
      el.setAttribute("font-size", size);
    }
  }, 50);
}

// ═══════════════════════════════════════════════════════════════════════════
// BUILD UI COMPONENTS
// ═══════════════════════════════════════════════════════════════════════════

// Gender thumbnails
function buildGenderGrid() {
  const container = document.getElementById("gender-grid");
  container.innerHTML = "";
  ["Female", "Male"].forEach(gen => {
    const el = document.createElement("div");
    el.className = "pc-option-item" + (state.gender === gen ? " selected" : "");
    el.dataset.id = gen;

    const thumb = document.createElement("div");
    thumb.className = "pc-thumb";
    const img = document.createElement("img");
    img.src = genderPreview(gen); img.alt = gen;
    img.onerror = () => { thumb.classList.add("placeholder"); img.remove(); };
    thumb.appendChild(img);
    el.appendChild(thumb);

    const label = document.createElement("div");
    label.className = "pc-option-label";
    label.textContent = gen;
    el.appendChild(label);

    el.addEventListener("click", () => {
      state.gender = gen;
      // Reset hair to first style for new gender
      state.hair = HAIRSTYLES[gen][0];
      render();
      // Rebuild all gender-dependent sections
      buildGenderGrid();
      buildThumbGrid("hair-grid", HAIRSTYLES[gen], () => state.hair,
        v => { state.hair = v; }, s => hairPreview(state.hairColor, s));
      buildThumbGrid("clothes-grid", OUTFITS, () => state.outfit,
        v => { state.outfit = v; }, o => outfitPreview(o));
      buildThumbGrid("acc-grid", ACCESSORIES, () => state.accessory,
        v => { state.accessory = v; }, a => a === "None" ? null : accPreview(a));
    });
    container.appendChild(el);
  });
}

// Circular swatches (skin tone + hair colour)
function buildSwatchRow(containerId, items, getSelected, onSelect) {
  const container = document.getElementById(containerId);
  container.innerHTML = "";
  items.forEach(item => {
    const el = document.createElement("div");
    el.className = "pc-swatch" + (getSelected() === item.id ? " selected" : "");
    el.dataset.id = item.id;
    el.style.background = item.color;
    el.title = item.id;
    el.addEventListener("click", () => {
      onSelect(item.id);
      container.querySelectorAll(".pc-swatch").forEach(s => s.classList.toggle("selected", s.dataset.id === getSelected()));
    });
    container.appendChild(el);
  });
}

// Thumbnail grid using preview images
function buildThumbGrid(containerId, items, getSelected, onSelect, previewFn) {
  const container = document.getElementById(containerId);
  container.innerHTML = "";
  items.forEach(item => {
    const isNone = item === "None";
    const el = document.createElement("div");
    el.className = "pc-option-item" + (getSelected() === item ? " selected" : "");
    el.dataset.id = item;

    const thumb = document.createElement("div");
    thumb.className = "pc-thumb" + (isNone ? " placeholder" : "");

    if (isNone) {
      thumb.textContent = "✕";
    } else {
      const img = document.createElement("img");
      img.src = previewFn(item); img.alt = item;
      img.onerror = () => { thumb.classList.add("placeholder"); img.remove(); };
      thumb.appendChild(img);
    }
    el.appendChild(thumb);

    const label = document.createElement("div");
    label.className = "pc-option-label";
    label.textContent = item;
    el.appendChild(label);

    el.addEventListener("click", () => {
      onSelect(item); render();
      container.querySelectorAll(".pc-option-item").forEach(e => e.classList.toggle("selected", e.dataset.id === getSelected()));
    });
    container.appendChild(el);
  });
}

// Text colour row
function buildTextColorRow(containerId, getSelected, onSelect) {
  const container = document.getElementById(containerId);
  container.innerHTML = "";
  [{ hex: DEFAULT_TEXT_COLOR, label: "Ink" }, ...BRAND_COLORS].forEach(c => {
    const btn = document.createElement("div");
    btn.className = "pc-text-swatch" + (getSelected() === c.hex ? " selected" : "");
    btn.dataset.hex = c.hex;
    btn.textContent = "A";
    btn.style.color = c.hex;
    btn.title = c.label;
    if (c.hex === "#FFFFFF") btn.style.textShadow = "0 0 0 1px #ddd";
    btn.addEventListener("click", () => {
      onSelect(c.hex); render();
      container.querySelectorAll(".pc-text-swatch").forEach(e => e.classList.toggle("selected", e.dataset.hex === getSelected()));
    });
    container.appendChild(btn);
  });
}

// Glasses toggle
let glassesListenerAdded = false;
function initGlassesToggle() {
  glassesToggle.checked = state.glasses;
  glassesLabel.textContent = state.glasses ? "Yes" : "No";
  if (!glassesListenerAdded) {
    glassesToggle.addEventListener("change", () => {
      state.glasses = glassesToggle.checked;
      glassesLabel.textContent = state.glasses ? "Yes" : "No";
      render();
    });
    glassesListenerAdded = true;
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// EXPORT
// ═══════════════════════════════════════════════════════════════════════════
async function exportCard() {
  saveBtn.disabled = true;
  saveBtn.textContent = "Preparing…";
  try {
    await document.fonts.ready;
    const canvas = document.createElement("canvas");
    canvas.width = PRINT_W; canvas.height = PRINT_H;
    const ctx = canvas.getContext("2d");

    const drawImg = src => new Promise(resolve => {
      if (!src) return resolve();
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.onload  = () => { ctx.drawImage(img, 0, 0, PRINT_W, PRINT_H); resolve(); };
      img.onerror = () => resolve();
      img.src = src;
    });

    await drawImg(WATERMARK_SRC);
    await drawImg(skinSrc());
    await drawImg(outfitSrc());
    if (state.hair !== "None") await drawImg(hairSrc());
    if (state.glasses) await drawImg(glassesSrc());
    if (state.accessory !== "None") await drawImg(accSrc());

    const maxW = PRINT_W * 0.82;
    ctx.textAlign = "center";
    ctx.fillStyle = state.textColor;

    if (state.recipient.trim()) {
      const str = state.recipient.toUpperCase();
      ctx.font = "400 22px Lora, Georgia, serif";
      ctx.letterSpacing = "2px";
      ctx.textBaseline = "alphabetic";
      ctx.fillText(str, PRINT_W / 2, PRINT_H * 0.76 + 42);
      ctx.letterSpacing = "0px";
    }

    if (state.message.trim()) {
      const str = state.message;
      let fs = 64;
      ctx.font = fs + 'px "De Lionist", Georgia, serif';
      while (ctx.measureText(str).width > maxW && fs > 32) {
        fs -= 2;
        ctx.font = fs + 'px "De Lionist", Georgia, serif';
      }
      ctx.textBaseline = "alphabetic";
      ctx.fillText(str, PRINT_W / 2, PRINT_H * 0.855 + 42);
    }

    const fileName = (state.recipient.trim() || "card") + ".png";
    const blob = await new Promise(r => canvas.toBlob(r, "image/png"));
    const file = new File([blob], fileName, { type: "image/png" });

    if (navigator.canShare && navigator.canShare({ files: [file] })) {
      try { await navigator.share({ files: [file], title: "My Card" }); showToast("Shared! Check AirDrop.", "success"); return; }
      catch (e) { if (e.name === "AbortError") return; }
    }
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a"); a.href = url; a.download = fileName; a.click();
    URL.revokeObjectURL(url);
    showToast("Saved! Open Safari to use AirDrop.", "info");

  } catch (e) {
    showToast("Something went wrong.", "error");
    console.error(e);
  } finally {
    saveBtn.disabled = false;
    saveBtn.textContent = "Save & AirDrop";
  }
}

function showToast(text, type) {
  const existing = document.getElementById("toast");
  if (existing) existing.remove();
  const bg = { success: "#2AA84A", info: "#3351c6", error: "#c2221b" }[type] || "#3351c6";
  const t = document.createElement("div");
  t.id = "toast"; t.textContent = text;
  t.style.cssText = `position:fixed;bottom:24px;left:50%;transform:translateX(-50%);background:${bg};color:#fff;font-family:system-ui;font-size:13px;font-weight:600;padding:12px 22px;border-radius:20px;box-shadow:0 4px 20px rgba(0,0,0,0.18);z-index:9999;white-space:nowrap;animation:fadeUp 0.2s ease`;
  const s = document.createElement("style");
  s.textContent = `@keyframes fadeUp{from{opacity:0;transform:translateX(-50%) translateY(8px)}to{opacity:1;transform:translateX(-50%) translateY(0)}}`;
  document.head.appendChild(s);
  document.body.appendChild(t);
  setTimeout(() => t.remove(), 4000);
}

if ("serviceWorker" in navigator) { navigator.serviceWorker.register("sw.js").catch(() => {}); }

// ═══════════════════════════════════════════════════════════════════════════
// RESET
// ═══════════════════════════════════════════════════════════════════════════
function resetApp() {
  state.gender    = "Female";
  state.skin      = "Fair";
  state.glasses   = false;
  state.hairColor = "Black";
  state.hair      = HAIRSTYLES[state.gender][0];
  state.outfit    = "Smart";
  state.accessory = "None";
  state.recipient = "";
  state.message   = "";
  state.textColor = DEFAULT_TEXT_COLOR;
  recipientInput.value = "";
  messageInput.value   = "";
  recipientCount.textContent = "0 / 30";
  messageCount.textContent   = "0 / 60";
  init();
}

// ═══════════════════════════════════════════════════════════════════════════
// INIT
// ═══════════════════════════════════════════════════════════════════════════
function init() {
  buildGenderGrid();

  buildSwatchRow("skin-grid", SKIN_TONES, () => state.skin, v => {
    state.skin = v; render();
    document.getElementById("skin-grid").querySelectorAll(".pc-swatch")
      .forEach(s => s.classList.toggle("selected", s.dataset.id === state.skin));
  });

  initGlassesToggle();

  buildSwatchRow("hair-color-grid", HAIR_COLORS, () => state.hairColor, v => {
    state.hairColor = v;
    render();
    buildThumbGrid("hair-grid", HAIRSTYLES[state.gender], () => state.hair,
      s => { state.hair = s; }, s => hairPreview(state.hairColor, s));
  });

  buildThumbGrid("hair-grid", HAIRSTYLES[state.gender], () => state.hair,
    v => { state.hair = v; }, s => hairPreview(state.hairColor, s));

  buildThumbGrid("clothes-grid", OUTFITS, () => state.outfit,
    v => { state.outfit = v; }, o => outfitPreview(o));

  buildThumbGrid("acc-grid", ACCESSORIES, () => state.accessory,
    v => { state.accessory = v; }, a => a === "None" ? null : accPreview(a));

  recipientInput.value = state.recipient;
  recipientInput.addEventListener("input", () => {
    state.recipient = recipientInput.value;
    recipientCount.textContent = recipientInput.value.length + " / 30";
    render();
  });
  messageInput.value = state.message;
  messageInput.addEventListener("input", () => {
    state.message = messageInput.value;
    messageCount.textContent = messageInput.value.length + " / 60";
    render();
  });

  saveBtn.addEventListener("click", exportCard);
  resetBtn.addEventListener("click", resetApp);
  render();
}


// De Lionist embedded font
(function() {
  var f = new FontFace('De Lionist', 'url(data:font/otf;base64,)', { style:'normal', weight:'normal' });
  f.load().then(function(l) { document.fonts.add(l); }).catch(function() {});
})();

init();
